const https = require('https');

function nocoRequest(method, path, body) {
  return new Promise((resolve, reject) => {
    const options = {
      hostname: 'nocodb.pressco21.com',
      path: '/api/v1/db/data/noco/' + $env.NOCODB_PROJECT_ID + path,
      method: method,
      headers: {
        'xc-token': $env.NOCODB_API_TOKEN,
        'Content-Type': 'application/json'
      }
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        try { resolve(JSON.parse(data)); } catch(e) { resolve(data); }
      });
    });
    req.on('error', reject);
    if (body) req.write(JSON.stringify(body));
    req.end();
  });
}

function sanitizeText(str, maxLen) {
  if (!str) return '';
  maxLen = maxLen || 500;
  return String(str)
    .replace(/[\u0000-\b\u000b\f\u000e-\u001f]/g, '')
    .trim()
    .substring(0, maxLen);
}

function extractBrandUid(raw) {
  const text = String(raw || '').replace(/\s+/g, '').trim();
  const match = text.match(/[?&]branduid=([^&#]+)/i);
  if (match && match[1]) return decodeURIComponent(match[1]);
  if (/^[A-Za-z0-9_-]{4,64}$/.test(text)) return text;
  return '';
}

function normalizeKitProductUrl(raw) {
  const text = sanitizeText(raw, 2048);
  if (!text) return '';
  const brandUid = extractBrandUid(text);
  if (brandUid) {
    return '/shop/shopdetail.html?branduid=' + encodeURIComponent(brandUid);
  }
  const lower = text.toLowerCase();
  if (lower.startsWith('http://') || lower.startsWith('https://') || text.indexOf('/shop/') === 0) {
    return text.substring(0, 2048);
  }
  return '';
}

function normalizeKitItems(rawItems) {
  if (!Array.isArray(rawItems)) return [];
  return rawItems.slice(0, 20).map((item) => ({
    name: sanitizeText(item && item.name, 100),
    product_url: normalizeKitProductUrl(item && (item.product_url || item.product_code || '')),
    quantity: Math.min(Math.max(parseInt(item && item.quantity, 10) || 1, 1), 99),
    price: Math.max(parseInt(item && item.price, 10) || 0, 0)
  })).filter((item) => item.name || item.product_url);
}

const input = $input.first().json;
const body = input.body || input || {};
const memberId = sanitizeText(body.member_id, 100);
const classId = sanitizeText(body.class_id, 100);

try {
  if (!memberId || !classId) {
    return [{json: {success: false, message: 'member_id and class_id required', statusCode: 400}}];
  }

  const partners = await nocoRequest('GET', '/mp8t0yq15cabmj4?where=(member_id,eq,' + encodeURIComponent(memberId) + ')~and(status,eq,active)&limit=1');
  if (!partners.list || partners.list.length === 0) {
    return [{json: {success: false, message: 'not an active partner', statusCode: 403}}];
  }
  const partner = partners.list[0];

  const classes = await nocoRequest('GET', '/mpvsno4or6asbxk?where=(class_id,eq,' + encodeURIComponent(classId) + ')~and(partner_code,eq,' + encodeURIComponent(partner.partner_code) + ')&limit=1');
  if (!classes.list || classes.list.length === 0) {
    return [{json: {success: false, message: 'class not found or not owned by you', statusCode: 403}}];
  }
  const cls = classes.list[0];

  const allowedFields = ['class_name', 'description', 'price', 'category', 'level', 'duration_min', 'max_students', 'thumbnail_url', 'image_urls', 'instructor_bio', 'location', 'materials_included', 'youtube_video_id', 'tags', 'kit_enabled', 'kit_items', 'kit_bundle_branduid'];
  const updateData = {};
  let hasChanges = false;

  for (const field of allowedFields) {
    if (body[field] !== undefined && body[field] !== null) {
      updateData[field] = body[field];
      hasChanges = true;
    }
  }

  if (!hasChanges) {
    return [{json: {success: false, message: 'no fields to update', statusCode: 400}}];
  }

  const nextKitEnabled = updateData.kit_enabled !== undefined ? (Number(updateData.kit_enabled) === 1 ? 1 : 0) : (Number(cls.kit_enabled) || 0);
  if (updateData.kit_enabled !== undefined) {
    updateData.kit_enabled = nextKitEnabled;
  }

  if (updateData.kit_items !== undefined) {
    const normalizedKitItems = normalizeKitItems(updateData.kit_items);
    if (nextKitEnabled === 1) {
      if (normalizedKitItems.length === 0) {
        return [{json: {success: false, message: 'kit item required when kit is enabled', statusCode: 400}}];
      }
      for (const item of normalizedKitItems) {
        if (!item.name || !item.product_url) {
          return [{json: {success: false, message: 'invalid kit item', statusCode: 400}}];
        }
      }
    }
    updateData.kit_items = JSON.stringify(normalizedKitItems);
  }

  if (updateData.kit_bundle_branduid !== undefined) {
    const normalizedBundleBrandUid = extractBrandUid(updateData.kit_bundle_branduid || '');
    if (String(updateData.kit_bundle_branduid || '').trim() && !normalizedBundleBrandUid) {
      return [{json: {success: false, message: 'invalid kit bundle branduid', statusCode: 400}}];
    }
    updateData.kit_bundle_branduid = nextKitEnabled === 1 ? normalizedBundleBrandUid : '';
  }

  if (updateData.price !== undefined) {
    const p = Number(updateData.price);
    if (isNaN(p) || p < 0) {
      return [{json: {success: false, message: 'invalid price', statusCode: 400}}];
    }
    updateData.price = p;
  }

  await nocoRequest('PATCH', '/mpvsno4or6asbxk/' + cls.Id, updateData);

  return [{json: {
    success: true,
    message: 'class updated',
    data: { class_id: classId, updated_fields: Object.keys(updateData) },
    statusCode: 200
  }}];

} catch(e) {
  return [{json: {success: false, message: 'Internal error: ' + e.message, statusCode: 500}}];
}
